        this.left = left;
        this.right = right;
    }
}

class Solution {
    // Function to calculate minimum time to burn the entire tree from the target node
    minTime(root, target) {
        // Map to represent the binary tree as an undirected graph
        const graph = new Map();

        // Convert binary tree to graph format
        this.buildGraph(root, null, graph);

        // Set to track visited (burned) nodes
        const visited = new Set();

        // Queue for BFS from the target node
        const queue = [target];
        visited.add(target);

        // Time to burn the entire tree
        let time = 0;

        // BFS level-order traversal
        while (queue.length > 0) {
            let size = queue.length;
            let burned = false;

            // Traverse all nodes at this level
            for (let i = 0; i < size; i++) {
                let node = queue.shift();

                // Visit all adjacent (connected) nodes
                for (let neighbor of (graph.get(node) || [])) {
                    if (!visited.has(neighbor)) {
                        visited.add(neighbor);
                        queue.push(neighbor);
                        burned = true;
                    }
                }
            }

            // If any nodes burned this second, increment time
            if (burned) time++;
        }

        return time;
    }

    // Helper method to build undirected graph from binary tree
    buildGraph(node, parent, graph) {
        if (!node) return;

        // Create bidirectional connection if parent exists
        if (parent) {
            graph.set(node.val, (graph.get(node.val) || []).concat(parent.val));
            graph.set(parent.val, (graph.get(parent.val) || []).concat(node.val));
        }

        // Recursively process left and right children
        this.buildGraph(node.left, node, graph);
        this.buildGraph(node.right, node, graph);
    }
}

